    size_t param_len = strnlen(msg_body, (size_t)body_len);

    /* 
     * Check if the string parameter fits in the destination buffer.
     * We need space for the string content plus the null terminator.
     */
    if (param_len >= (size_t)buffer_size) {
        return -1;
    }

    /* 
     * Safely copy the parameter into the buffer.
     * Since we have verified that param_len < buffer_size, 
     * param_len + 1 is guaranteed to be <= buffer_size.
     * We copy param_len + 1 bytes to include the null terminator 
     * if it exists within the body_len, or to explicitly null-terminate 
     * if the string filled the entire body_len.
     */
    memcpy(param_buffer, msg_body, param_len + 1);

    /* Ensure null termination in case the source was not null-terminated */
    param_buffer[param_len] = '\0';

    return 0;
}
